//! Fixture replay for the enterprise drill baseline projection.
//!
//! The fixtures live under `fixtures/security/m3/drill_inputs/` and are
//! generated by the `aureline_shell_enterprise_drill_baseline` headless
//! inspector, so checked-in JSON stays a literal projection of the seeded
//! `EnterpriseDrillBaselinePage`.

use aureline_shell::enterprise_drill_baseline::{
    seeded_enterprise_drill_baseline_page, validate_enterprise_drill_baseline_page,
    EnterpriseDrillBaselinePage, EnterpriseDrillBaselineRenderSummary,
    EnterpriseDrillBaselineSupportExport, EnterpriseDrillKindClass, EnterpriseDrillPacket,
    EnterpriseRowFamilyClass, ENTERPRISE_DRILL_BASELINE_SCHEMA_VERSION,
    ENTERPRISE_DRILL_BASELINE_SHARED_CONTRACT_REF,
};

const FIXTURE_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../fixtures/security/m3/drill_inputs"
);

const ARTIFACT_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../artifacts/security/m3/backup_restore_failover_drills"
);

fn load<T: serde::de::DeserializeOwned>(filename: &str) -> T {
    let path = format!("{}/{}", FIXTURE_DIR, filename);
    let body = std::fs::read_to_string(&path)
        .unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

fn load_artifact<T: serde::de::DeserializeOwned>(filename: &str) -> T {
    let path = format!("{}/{}", ARTIFACT_DIR, filename);
    let body = std::fs::read_to_string(&path)
        .unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

#[test]
fn page_fixture_matches_seeded_builder() {
    let from_file: EnterpriseDrillBaselinePage = load("page.json");
    let from_code = seeded_enterprise_drill_baseline_page();
    assert_eq!(
        from_file, from_code,
        "fixture must be a literal projection of the seeded page; regenerate via the headless bin"
    );
}

#[test]
fn page_fixture_validates_with_zero_defects() {
    let page: EnterpriseDrillBaselinePage = load("page.json");
    assert_eq!(
        page.shared_contract_ref,
        ENTERPRISE_DRILL_BASELINE_SHARED_CONTRACT_REF
    );
    assert_eq!(
        page.schema_version,
        ENTERPRISE_DRILL_BASELINE_SCHEMA_VERSION
    );
    assert!(page.defects.is_empty());
    validate_enterprise_drill_baseline_page(&page).expect("seeded page must validate");
}

#[test]
fn drill_packets_fixture_matches_page() {
    let page: EnterpriseDrillBaselinePage = load("page.json");
    let packets: Vec<EnterpriseDrillPacket> = load("drill_packets.json");
    assert_eq!(page.drill_packets, packets);
}

#[test]
fn every_family_has_every_drill_kind() {
    let page: EnterpriseDrillBaselinePage = load("page.json");
    for family in EnterpriseRowFamilyClass::ALL {
        for kind in EnterpriseDrillKindClass::ALL {
            let found = page
                .drill_packets
                .iter()
                .any(|packet| packet.row_family == family && packet.drill_kind == kind);
            assert!(
                found,
                "fixture is missing a {} drill packet for row family {}",
                kind.as_str(),
                family.as_str()
            );
        }
    }
}

#[test]
fn artifact_per_packet_matches_page() {
    let page: EnterpriseDrillBaselinePage = load("page.json");
    for packet in &page.drill_packets {
        let file = packet
            .artifact_ref
            .rsplit('/')
            .next()
            .expect("artifact_ref names a file");
        let from_artifact: EnterpriseDrillPacket = load_artifact(file);
        assert_eq!(*packet, from_artifact, "{}", packet.drill_packet_id);
    }
}

#[test]
fn support_export_round_trips_through_validator() {
    let export: EnterpriseDrillBaselineSupportExport = load("support_export.json");
    assert!(export.raw_private_material_excluded);
    assert!(export.no_public_endpoint_fallback_invariant);
    assert!(export.local_editing_preserved_invariant);
    assert!(export.sibling_lanes_unwidened_invariant);
    assert!(export.defect_kinds_present.is_empty());
    assert_eq!(
        export.shared_contract_ref,
        ENTERPRISE_DRILL_BASELINE_SHARED_CONTRACT_REF
    );
}

#[test]
fn render_summary_matches_page_summary() {
    let from_file: EnterpriseDrillBaselineRenderSummary = load("render_summary.json");
    let page: EnterpriseDrillBaselinePage = load("page.json");
    let from_page = EnterpriseDrillBaselineRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
